import React from "react";

const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Fraunces:ital,opsz,wght@0,9..144,300;0,9..144,400;0,9..144,500;0,9..144,600;1,9..144,400;1,9..144,500&family=Petit+Formal+Script&display=swap');

.mdc-page {
  background: #E3D4B7;
  background-image:
    radial-gradient(circle at 15% 20%, rgba(178,85,72,0.07), transparent 45%),
    radial-gradient(circle at 85% 80%, rgba(201,162,99,0.10), transparent 50%);
  font-family: 'Fraunces', Georgia, serif;
  color: #3A2A22;
  padding: 48px 20px;
  min-height: 100vh;
  width: 100%;
  box-sizing: border-box;
}
.mdc-page * { box-sizing: border-box; }

.mdc-card {
  max-width: 720px;
  margin: 0 auto;
  background: #FBF2E4;
  background-image:
    url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='240' height='240'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='2' seed='7'/><feColorMatrix values='0 0 0 0 0.20  0 0 0 0 0.15  0 0 0 0 0.12  0 0 0 0.18 0'/></filter><rect width='240' height='240' filter='url(%23n)'/></svg>"),
    radial-gradient(ellipse 110% 60% at 50% 0%, rgba(255, 244, 220, 0.7), transparent),
    radial-gradient(ellipse 90% 50% at 50% 100%, rgba(178,85,72,0.06), transparent);
  background-size: 240px, 100% 100%, 100% 100%;
  padding: 56px 48px 48px;
  box-shadow:
    inset 0 1px 0 rgba(255,255,255,0.4),
    0 30px 80px -20px rgba(58, 42, 34, 0.35),
    0 12px 32px -10px rgba(58, 42, 34, 0.20);
  border: 1px solid rgba(58, 42, 34, 0.08);
  border-radius: 4px;
  position: relative;
}

.mdc-corner {
  position: absolute; width: 28px; height: 28px;
  color: #B25548; opacity: 0.7;
}
.mdc-corner.tl { top: 14px; left: 14px; }
.mdc-corner.tr { top: 14px; right: 14px; transform: scaleX(-1); }
.mdc-corner.bl { bottom: 14px; left: 14px; transform: scaleY(-1); }
.mdc-corner.br { bottom: 14px; right: 14px; transform: scale(-1, -1); }

.mdc-header { text-align: center; margin-bottom: 36px; }
.mdc-eyebrow {
  display: inline-flex; align-items: center; gap: 14px;
  font-family: 'Fraunces', serif;
  font-size: 11px; font-weight: 600;
  letter-spacing: 0.42em; text-transform: uppercase;
  color: #B25548; margin-bottom: 14px;
}
.mdc-eyebrow::before, .mdc-eyebrow::after {
  content: ''; display: block; width: 38px; height: 1px;
  background: #B25548; opacity: 0.55;
}
.mdc-h1 {
  font-family: 'Fraunces', serif;
  font-weight: 400; font-style: italic;
  font-size: 60px; line-height: 1.0;
  margin: 0; letter-spacing: -0.015em;
  font-variation-settings: 'opsz' 144, 'SOFT' 60;
  color: #3A2A22;
}
.mdc-stars {
  display: flex; align-items: center; justify-content: center;
  gap: 8px; margin-top: 18px;
  color: #C9A263; font-size: 14px; letter-spacing: 0.5em;
}

.mdc-photos {
  display: flex; flex-direction: column;
  gap: 44px; margin: 18px 0 44px;
}
.mdc-photo {
  background: #FFFEFA;
  padding: 18px 18px 36px;
  box-shadow:
    0 28px 56px -16px rgba(58, 42, 34, 0.42),
    0 10px 22px -6px rgba(58, 42, 34, 0.22),
    inset 0 0 0 1px rgba(58, 42, 34, 0.04);
  position: relative;
  margin: 0;
}
.mdc-photo:nth-child(1) { transform: rotate(-1.8deg); }
.mdc-photo:nth-child(2) { transform: rotate(1.4deg); }
.mdc-photo::before {
  content: ''; position: absolute;
  top: -12px; left: 50%; width: 90px; height: 24px;
  background: rgba(220, 195, 130, 0.5);
  transform: translateX(-50%) rotate(-2deg);
  border-left: 1px dashed rgba(58, 42, 34, 0.15);
  border-right: 1px dashed rgba(58, 42, 34, 0.15);
}
.mdc-photo:nth-child(2)::before {
  transform: translateX(-50%) rotate(3deg);
  background: rgba(178, 85, 72, 0.28);
}
.mdc-photo img { display: block; width: 100%; height: auto; }

.mdc-finale {
  text-align: center; margin-top: 40px;
  padding-top: 32px;
  border-top: 1px dashed rgba(58, 42, 34, 0.18);
}
.mdc-love {
  font-family: 'Petit Formal Script', 'Pinyon Script', cursive;
  font-weight: 400; font-size: 64px;
  color: #B25548; margin: 0; line-height: 1;
  text-shadow: 0 1px 0 rgba(255, 244, 220, 0.5);
}
.mdc-illustration {
  margin: 18px auto 12px; display: block;
  width: 88%; max-width: 420px; height: auto;
}
.mdc-three-line {
  display: flex; align-items: center; justify-content: center;
  gap: 14px; margin-top: 8px;
}
.mdc-dash {
  flex: 0 0 44px; height: 1px;
  background: #B25548; opacity: 0.5;
}
.mdc-three-line p {
  font-family: 'Fraunces', serif;
  font-style: italic; font-weight: 500;
  font-size: 20px; color: #3A2A22;
  opacity: 0.78; margin: 0; letter-spacing: 0.04em;
}
.mdc-signoff {
  text-align: center; margin-top: 24px;
  font-family: 'Fraunces', serif;
  font-size: 11px; letter-spacing: 0.4em;
  text-transform: uppercase;
  color: #3A2A22; opacity: 0.4;
}
.mdc-signoff::before, .mdc-signoff::after {
  content: '✦'; margin: 0 12px;
  color: #B25548; opacity: 0.7;
}

@media print {
  .mdc-page { background: none; padding: 0; }
  .mdc-card { box-shadow: none; max-width: none; width: 100%; border: none; border-radius: 0; }
  @page { margin: 14mm; }
}
@media (max-width: 700px) {
  .mdc-page { padding: 20px 12px; }
  .mdc-card { padding: 36px 24px 32px; }
  .mdc-h1 { font-size: 42px; }
  .mdc-love { font-size: 48px; }
}
`;

